/* 文件头注释：使用BFS算法寻找从1到p/q的最短路径 */
#include <bits/stdc++.h>
using namespace std;

// 定义有理数结构体
struct Rational {
    long long p, q;
    Rational(long long p = 0, long long q = 1) : p(p), q(q) {}
    bool operator==(const Rational& other) const {
        return p == other.p && q == other.q;
    }
    bool operator<(const Rational& other) const {
        return p * other.q < other.p * q;
    }
};

// 定义节点结构体
struct Node {
    Rational val;
    string path;
    Node(Rational val, string path) : val(val), path(path) {}
};

// 计算最大公约数
long long gcd(long long a, long long b) {
    return b == 0 ? a : gcd(b, a % b);
}

// BFS函数
string bfs(Rational target) {
    queue<Node> q;
    q.push(Node(Rational(1, 1), ""));

    while (!q.empty()) {
        Node current = q.front();
        q.pop();

        if (current.val == target) {
            return current.path;
        }

        // 向左走
        Rational left(current.val.p + current.val.q, current.val.q);
        q.push(Node(left, current.path + "L"));

        // 向右走
        Rational right(current.val.p, current.val.p + current.val.q);
        q.push(Node(right, current.path + "R"));
    }

    return "";
}

int main() {
    long long p, q;
    cin >> p >> q;

    Rational target(p, q);
    string path = bfs(target);

    cout << path << endl;

    return 0;
}

[报错信息/测试反馈]
内存超限

